import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('Authorization')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
    except (TypeError, ValueError):
        return None
    try:
        token_str = decoded.decode('utf-8')
        token_obj = json.loads(token_str)
    except (UnicodeDecodeError, json.JSONDecodeError):
        return None
    if token_obj.get('valid') is True and 'data' in token_obj:
        return token_obj['data']
    else:
        return None
